import { useState, useRef } from "react";

const LORI_QR = "";
const LORI_AUDIO = "data:audio/mp4;base64,";
const P1 = "data:image/jpeg;base64,";
const P2 = "data:image/jpeg;base64,";
const P3 = "data:image/jpeg;base64,";
const P4 = "data:image/jpeg;base64,";
const M1 = "data:image/jpeg;base64,";
const M2 = "data:image/jpeg;base64,";
const M3 = "data:image/jpeg;base64,";
const M4 = "data:image/jpeg;base64,";

const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400;1,700&family=DM+Sans:wght@300;400;500;600&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root { --ink: #12112A; --blush: #F0C4C4; --coral: #D95F5F; --canvas: #FDF8F3; --muted: #8A8599; --white: #FFFFFF; --border: #EDE8E1; --bubble: #FFF5F5; }
  body { background: var(--canvas); color: var(--ink); font-family: 'DM Sans', sans-serif; min-height: 100vh; }
  .page { min-height: 100vh; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 2rem 1.25rem; }
  .nav { width: 100%; max-width: 520px; display: flex; justify-content: space-between; align-items: center; padding: 0 0 1.5rem; }
  .nav-logo { font-family: 'Playfair Display', serif; font-size: 1.1rem; font-style: italic; color: var(--coral); cursor: pointer; }
  .nav-link { font-size: 0.8rem; letter-spacing: 0.1em; text-transform: uppercase; color: var(--muted); text-decoration: none; font-weight: 500; cursor: pointer; }
  .nav-link:hover { color: var(--coral); }
  .card { background: var(--white); border-radius: 24px; padding: 2.5rem 2rem; max-width: 480px; width: 100%; box-shadow: 0 4px 32px rgba(18,17,42,0.07); }
  .profile-tagline { font-family: 'Playfair Display', serif; font-size: 1.3rem; line-height: 1.4; margin-bottom: 0.4rem; font-style: italic; }
  .profile-name { font-size: 0.75rem; letter-spacing: 0.15em; text-transform: uppercase; color: var(--coral); font-weight: 600; margin-bottom: 1.25rem; }
  .profile-ig { display: inline-flex; align-items: center; gap: 0.5rem; background: var(--ink); color: white; text-decoration: none; font-size: 0.85rem; font-weight: 500; padding: 0.65rem 1.4rem; border-radius: 100px; transition: background 0.2s; }
  .profile-ig:hover { background: var(--coral); }
  hr.divider { border: none; border-top: 1.5px solid var(--border); margin: 1.5rem 0; }
  .audio-player { width: 100%; margin: 1rem 0; border-radius: 12px; background: var(--bubble); padding: 0.75rem 1rem; display: flex; align-items: center; gap: 0.75rem; border: 1.5px solid var(--blush); }
  .audio-btn { width: 44px; height: 44px; border-radius: 50%; background: var(--coral); border: none; cursor: pointer; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
  .audio-btn:hover { background: #c04f4f; }
  .audio-label { font-size: 0.8rem; color: var(--muted); line-height: 1.4; }
  .audio-label strong { display: block; color: var(--ink); font-size: 0.85rem; }
  .friend-card { background: var(--bubble); border: 1.5px solid var(--blush); border-radius: 14px; padding: 1rem; text-align: center; cursor: pointer; transition: border-color 0.2s; }
  .friend-card:hover { border-color: var(--coral); }
  .friend-name { font-family: 'Playfair Display', serif; font-size: 1rem; margin-bottom: 0.2rem; }
  .friend-tag { font-size: 0.72rem; color: var(--muted); margin-bottom: 0.6rem; }
  .what-is-this { background: var(--bubble); border-left: 3px solid var(--blush); border-radius: 0 10px 10px 0; padding: 0.85rem 1rem; margin-bottom: 1.5rem; font-size: 0.82rem; color: var(--muted); line-height: 1.6; text-align: left; }
`;

function IgIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <rect x="2" y="2" width="20" height="20" rx="5" ry="5"/>
      <circle cx="12" cy="12" r="4"/>
      <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"/>
    </svg>
  );
}

function AudioPlayer() {
  const [playing, setPlaying] = useState(false);
  const audioRef = useRef(null);
  function toggle() {
    if (!audioRef.current) return;
    if (playing) { audioRef.current.pause(); setPlaying(false); }
    else { audioRef.current.play(); setPlaying(true); }
  }
  return (
    <div className="audio-player">
      <audio ref={audioRef} src={LORI_AUDIO} onEnded={() => setPlaying(false)} />
      <button className="audio-btn" onClick={toggle}>
        {playing
          ? <svg width="16" height="16" viewBox="0 0 24 24" fill="white"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>
          : <svg width="16" height="16" viewBox="0 0 24 24" fill="white"><polygon points="5,3 19,12 5,21"/></svg>}
      </button>
      <div className="audio-label">
        <strong>A word from Lori</strong>
        Hit play before you swipe away.
      </div>
    </div>
  );
}

function WhatIsThis() {
  return (
    <div style={{position:"relative",textAlign:"center",margin:"0 0 1.5rem",padding:"0.75rem 0"}}>
      <div style={{position:"absolute",top:"50%",left:0,right:0,height:"1px",background:"var(--blush)"}} />
      <span style={{position:"relative",background:"var(--white)",padding:"0 1rem",fontSize:"0.82rem",color:"var(--muted)",fontStyle:"italic"}}>
        single · bold · happy you're here
      </span>
    </div>
  );
}

function HomePage({ onNavigate }) {
  return (
    <div className="page">
      <nav className="nav">
        <span className="nav-logo">youscannedme</span>
      </nav>
      <div className="card">
        <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:"2.4rem",lineHeight:1.1,marginBottom:"0.75rem"}}>Put yourself <em style={{fontStyle:"italic",color:"var(--coral)"}}>out there.</em> Literally.</h1>
        <p style={{color:"var(--muted)",fontSize:"0.95rem",lineHeight:1.6,marginBottom:"2rem"}}>A QR code on your bag, your jacket, your coffee cup. Someone scans it. They land on your Instagram. You decide what happens next.</p>
        <button style={{display:"block",width:"100%",padding:"1rem",background:"var(--ink)",color:"white",border:"none",borderRadius:"14px",fontFamily:"'DM Sans',sans-serif",fontSize:"1rem",fontWeight:600,cursor:"pointer"}} onClick={() => onNavigate("lori")}>Meet Lori →</button>
      </div>
    </div>
  );
}

const PROFILES = {
  michelle: {
    name: "Michelle",
    slug: "michelle",
    ig: "mbarnesny",
    tagline: "Bold move. Let's see where this goes.",
    photos: [M1, M2, M3, M4],
    bio: [
      "Hi, I'm Michelle.",
      "Foodie, wine snob, traveler, and dog lover.",
      "I believe the best moments happen around a great meal or on an adventure somewhere new. Bonus points if there's good wine involved.",
      "If you're here, you're clearly someone who pays attention. I appreciate that."
    ]
  },
  stephanie: {
    name: "Stephanie",
    slug: "stephanie",
    ig: "vina_colorado",
    tagline: "Single. Verified. Mildly chaotic. Interested?",
    bio: [
      "Hi, I'm Stephanie.",
      "Urban farmer. Beekeeper. Dog mom. Interwebs marketer. Wino. Sci-fi nerd.",
      "I grow things, keep bees, and somehow also work in tech. My life is a lot. In the best way.",
      "If you scanned a QR code on a bag, you're probably my kind of person."
    ]
  }
};

function ProfilePage({ profile, onNavigate }) {
  const isLori = !profile || profile.slug === "lori";
  const prof = profile || {
    name: "Lori",
    slug: "lori",
    ig: "curlier_lori",
    tagline: "This is either a terrible idea or a great story.",
  };

  return (
    <div className="page" style={{paddingTop:"1.5rem",paddingBottom:"3rem"}}>
      <nav className="nav">
        <span className="nav-logo" onClick={() => onNavigate("home")}>youscannedme</span>
        <div style={{display:"flex",gap:"1rem"}}>
          {!isLori && <a className="nav-link" onClick={() => onNavigate("lori")}>← Lori</a>}
          {isLori && <a className="nav-link" onClick={() => onNavigate("home")}>← Home</a>}
        </div>
      </nav>
      <div className="card" style={{textAlign:"center"}}>

        <WhatIsThis />

        <p className="profile-tagline">"{prof.tagline}"</p>
        <p className="profile-name">— {prof.name}</p>

        {isLori && (
          <div style={{margin:"1rem 0"}}>
            <img src={P1} alt="Lori" style={{width:"100%",aspectRatio:"4/3",objectFit:"cover",objectPosition:"center 55%",borderRadius:"14px",marginBottom:"0.5rem"}} />
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:"0.5rem"}}>
              <img src={P2} alt="Broncos" style={{width:"100%",aspectRatio:"1/1",objectFit:"cover",objectPosition:"top",borderRadius:"10px"}} />
              <img src={P3} alt="Friends" style={{width:"100%",aspectRatio:"1/1",objectFit:"cover",objectPosition:"top",borderRadius:"10px"}} />
              <img src={P4} alt="Dinner" style={{width:"100%",aspectRatio:"1/1",objectFit:"cover",objectPosition:"top",borderRadius:"10px"}} />
            </div>
          </div>
        )}

        {!isLori && prof.photos && (
          <div style={{margin:"1rem 0"}}>
            <img src={prof.photos[0]} alt={prof.name} style={{width:"100%",aspectRatio:"4/3",objectFit:"cover",objectPosition:"center top",borderRadius:"14px",marginBottom:"0.5rem"}} />
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:"0.5rem"}}>
              {prof.photos.slice(1).map((src, i) => (
                <img key={i} src={src} alt={prof.name} style={{width:"100%",aspectRatio:"1/1",objectFit:"cover",objectPosition:"top",borderRadius:"10px"}} />
              ))}
            </div>
          </div>
        )}

        {isLori && <AudioPlayer />}

        <hr className="divider" />

        <div style={{textAlign:"left",fontSize:"0.9rem",lineHeight:1.75,color:"var(--ink)"}}>
          {isLori ? (
            <>
              <p style={{marginBottom:"0.75rem"}}>Hi, I'm Lori. I'm 47, I'm single, and I'm based in the Denver/Boulder, CO area. Yes — I put a QR code on my bag. (I also built this site.)</p>
              <p style={{marginBottom:"0.75rem"}}>Product leader. Gardener. Amateur chef. Community builder. Wine enthusiast. AI nerd. Broncos season ticket holder.</p>
              <p style={{marginBottom:"0.75rem"}}>I'm happiest creating spaces where people feel welcome — whether that's around a dinner table, in a garden, or over a great conversation.</p>
              <p>If you're curious enough to scan a stranger's QR code, we probably already have something in common.</p>
            </>
          ) : (
            prof.bio && prof.bio.map((line, i) => (
              <p key={i} style={{marginBottom: i < prof.bio.length - 1 ? "0.75rem" : 0}}>{line}</p>
            ))
          )}
        </div>

        <hr className="divider" />

        <p style={{fontFamily:"'Playfair Display',serif",fontSize:"1rem",marginBottom:"0.75rem"}}>Come say hi.</p>
        <a className="profile-ig" href={`https://instagram.com/${prof.ig}`} target="_blank" rel="noopener noreferrer">
          <IgIcon size={16} /> @{prof.ig}
        </a>
        <p style={{fontSize:"0.75rem",color:"var(--muted)",marginTop:"0.6rem"}}>
          Take a look, take your time - then come say hi.
        </p>

        {isLori && (
          <>
            <hr className="divider" />
            <p style={{fontFamily:"'Playfair Display',serif",fontSize:"1rem",marginBottom:"0.25rem"}}>Meet my friends.</p>
            <p style={{fontSize:"0.78rem",color:"var(--muted)",marginBottom:"0.75rem"}}>They are also out here, doing the thing.</p>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0.75rem"}}>
              <div className="friend-card" onClick={() => onNavigate("michelle")}>
                <p className="friend-name">Michelle</p>
                <p className="friend-tag">Foodie. Wine snob. Traveler. Dog lover.</p>
                <span style={{display:"inline-block",background:"var(--coral)",color:"white",fontSize:"0.75rem",fontWeight:500,padding:"0.4rem 0.85rem",borderRadius:"100px"}}>See her page</span>
              </div>
              <div className="friend-card" onClick={() => onNavigate("stephanie")}>
                <p className="friend-name">Stephanie</p>
                <p className="friend-tag">Urban farmer. Beekeeper. Wino. Sci-fi nerd.</p>
                <span style={{display:"inline-block",background:"var(--coral)",color:"white",fontSize:"0.75rem",fontWeight:500,padding:"0.4rem 0.85rem",borderRadius:"100px"}}>See her page</span>
              </div>
            </div>
            <p style={{fontSize:"0.7rem",color:"var(--muted)",marginTop:"2rem",textAlign:"center",fontStyle:"italic"}}>Built by Lori. Because of course she did.</p>
          </>
        )}
      </div>
    </div>
  );
}

function getInitialPage() {
  const path = window.location.pathname.replace("/", "").toLowerCase();
  if (path === "lori") return "lori";
  if (path === "michelle") return "michelle";
  if (path === "stephanie") return "stephanie";
  return "home";
}

export default function App() {
  const [page, setPage] = useState(getInitialPage);

  function navigate(to) {
    setPage(to);
    const pathMap = { home: "/", lori: "/lori", michelle: "/michelle", stephanie: "/stephanie" };
    window.history.pushState({}, "", pathMap[to] || "/");
    window.scrollTo(0, 0);
  }

  return (
    <>
      <style>{STYLES}</style>
      {page === "home" && <HomePage onNavigate={navigate} />}
      {page === "lori" && <ProfilePage profile={null} onNavigate={navigate} />}
      {page === "michelle" && <ProfilePage profile={PROFILES.michelle} onNavigate={navigate} />}
      {page === "stephanie" && <ProfilePage profile={PROFILES.stephanie} onNavigate={navigate} />}
    </>
  );
}
